package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class LineItemTest {

  private Object lineItem;

  @BeforeEach
  void setUp() throws Exception {
    Class<?> clazz = Class.forName("com.google.gson.examples.android.model.LineItem");
    lineItem = clazz.getConstructor(String.class, int.class, long.class, String.class)
        .newInstance("TestName", 5, 1000L, "USD");
  }

  @Test
  void testGetName() throws Exception {
    Class<?> clazz = lineItem.getClass();
    String name = (String) clazz.getMethod("getName").invoke(lineItem);
    assertEquals("TestName", name);
  }
}
